'use client';

import Link from 'next/link';
import {
  TrendingUp,
  Code,
  Video,
  BrainCircuit,
  Megaphone,
  Briefcase,
} from 'lucide-react';

interface ServiceCardProps {
  slug: string;
  icon: string;
  title: string;
  externalLink?: string;
}

const iconMap: Record<string, React.ReactNode> = {
  TrendingUp: <TrendingUp size={32} />,
  Code: <Code size={32} />,
  Video: <Video size={32} />,
  BrainCircuit: <BrainCircuit size={32} />,
  Megaphone: <Megaphone size={32} />,
  Briefcase: <Briefcase size={32} />,
};

export default function ServiceCard({
  slug,
  icon,
  title,
  externalLink,
}: ServiceCardProps) {
  const handleClick = (e: React.MouseEvent) => {
    if (externalLink) {
      e.preventDefault();
      window.open(externalLink, '_blank');
      // Also navigate to service page
      setTimeout(() => {
        window.location.href = `/services/${slug}`;
      }, 100);
    }
  };

  return (
    <Link href={`/services/${slug}`} onClick={handleClick}>
      <div className="service-card">
        <div className="service-card-icon">{iconMap[icon] || null}</div>
        <h3>{title}</h3>
      </div>
    </Link>
  );
}
